// frontend/src/components/auth/FingerprintAuth.js
import React, { useState, useEffect } from 'react';
import { useSensor } from '../../hooks/useSensor';
import './FingerprintAuth.css';

const FingerprintAuth = ({ onSuccess, onError, onEnroll }) => {
    const [status, setStatus] = useState('idle');
    const [message, setMessage] = useState('');
    const [enrollStep, setEnrollStep] = useState('');
    const { 
        status: sensorStatus, 
        loading, 
        connect, 
        disconnect,
        scanFingerprint,
        enrollFingerprint,
        isSupported,
    } = useSensor();

    useEffect(() => {
        return () => {
            if (sensorStatus.connected) {
                disconnect();
            }
        };
    }, [disconnect, sensorStatus.connected]);

    const handleConnect = async () => {
        setStatus('connecting');
        setMessage('Looking for USB fingerprint sensor...');
        
        const result = await connect();
        
        if (result.success) {
            setStatus('connected');
            setMessage('USB Sensor connected! Ready to scan.');
        } else {
            setStatus('error');
            setMessage(`Connection failed: ${result.error}`);
            if (onError) onError(result.error);
        }
    };

    const handleScan = async () => {
        setStatus('scanning');
        setMessage('Please place your finger on the sensor...');
        
        try {
            const result = await scanFingerprint();
            
            if (result.success) {
                setStatus('success');
                setMessage(`✅ Fingerprint recognized! User ID: ${result.userId}`);
                if (onSuccess) onSuccess(result);
            } else {
                setStatus('error');
                setMessage(`❌ Scan failed: ${result.error}`);
                if (onError) onError(result.error);
            }
        } catch (error) {
            setStatus('error');
            setMessage(`❌ Error: ${error.message}`);
            if (onError) onError(error);
        }
    };

    const handleEnroll = async () => {
        setStatus('enrolling');
        setMessage('Starting fingerprint enrollment...');
        setEnrollStep('');
        
        try {
            const result = await enrollFingerprint();
            
            if (result.success) {
                setStatus('success');
                setMessage(`✅ Fingerprint enrolled successfully! ID: ${result.userId}`);
                if (onEnroll) onEnroll(result);
            } else {
                setStatus('error');
                setMessage(`❌ Enrollment failed: ${result.error}`);
                if (onError) onError(result.error);
            }
        } catch (error) {
            setStatus('error');
            setMessage(`❌ Error: ${error.message}`);
            if (onError) onError(error);
        }
    };

    if (!isSupported) {
        return (
            <div className="auth-container">
                <div className="error-message">
                    ⚠️ Your browser does not support Web Serial API.
                    Please use Chrome or Edge browser.
                </div>
            </div>
        );
    }

    return (
        <div className="auth-container">
            <div className="fingerprint-card">
                <div className="fingerprint-animation">
                    <div className={`fingerprint-icon ${sensorStatus.connected ? 'connected' : ''} ${status}`}>
                        <svg viewBox="0 0 24 24">
                            <path d="M12 2C8.13 2 5 5.13 5 9v6c0 3.87 3.13 7 7 7s7-3.13 7-7V9c0-3.87-3.13-7-7-7z"/>
                        </svg>
                    </div>
                </div>

                <div className="status-section">
                    {!sensorStatus.connected ? (
                        <button 
                            className="btn-primary"
                            onClick={handleConnect}
                            disabled={loading}
                        >
                            {loading ? 'Connecting...' : '🔌 Connect USB Fingerprint Sensor'}
                        </button>
                    ) : (
                        <>
                            <div className="sensor-badge">
                                <span className="sensor-dot"></span>
                                USB Sensor Connected
                            </div>
                            <div className="button-group">
                                <button 
                                    className="btn-primary"
                                    onClick={handleScan}
                                    disabled={loading}
                                >
                                    {loading ? 'Scanning...' : '🔍 Scan Fingerprint'}
                                </button>
                                <button 
                                    className="btn-secondary"
                                    onClick={handleEnroll}
                                    disabled={loading}
                                >
                                    {loading ? 'Enrolling...' : '📝 Enroll Fingerprint'}
                                </button>
                                <button 
                                    className="btn-secondary"
                                    onClick={disconnect}
                                    disabled={loading}
                                >
                                    Disconnect
                                </button>
                            </div>
                        </>
                    )}
                </div>

                {enrollStep && (
                    <div className="enroll-step">
                        <div className="step-indicator"></div>
                        <p>{enrollStep}</p>
                    </div>
                )}

                {message && (
                    <div className={`status-message ${status}`}>
                        {message}
                    </div>
                )}
            </div>
        </div>
    );
};

export default FingerprintAuth;
